import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { sendOtp, verifyOtp, checkRiderApproval } from "../services/api"; // ensure correct path
import {
  Box,
  Button,
  Container,
  TextField,
  Typography,
  Alert,
  CircularProgress,
} from "@mui/material";

export default function RiderLogin() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1 = mobile, 2 = OTP
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: "", text: "" });
  const navigate = useNavigate();

  // Step 1: Send OTP only if rider approved
  const handleSendOtp = async () => {
    setMessage({ type: "", text: "" });

    if (!mobile || mobile.length < 10) {
      setMessage({ type: "error", text: "Enter a valid mobile number." });
      return;
    }

    try {
      setLoading(true);

      // Check rider approval
      const approvalRes = await checkRiderApproval(mobile);
      if (!approvalRes.data?.approved) {
        setMessage({ type: "error", text: "Your account is pending admin approval." });
        setLoading(false);
        return;
      }

      // Send OTP
      const res = await sendOtp(mobile, "rider");
      if (res.data.success) {
        setStep(2);
        setMessage({ type: "success", text: "OTP sent! Check your mobile." });
      } else {
        setMessage({ type: "error", text: res.data.message || "Failed to send OTP" });
      }

    } catch (err) {
      setMessage({ type: "error", text: "Server error while sending OTP." });
    } finally {
      setLoading(false);
    }
  };

  // Step 2: Verify OTP
  const handleVerifyOtp = async () => {
    setMessage({ type: "", text: "" });

    if (!otp || otp.length < 4) {
      setMessage({ type: "error", text: "Enter a valid OTP." });
      return;
    }

    try {
      setLoading(true);
      const res = await verifyOtp(mobile, otp, "rider");
      if (res.data.success) {
        localStorage.setItem("token", res.data.token || "dummy-token");
        localStorage.setItem("role", "rider");
        navigate("/rider-dashboard");
      } else {
        setMessage({ type: "error", text: res.data.message || "Invalid OTP." });
      }
    } catch (err) {
      setMessage({ type: "error", text: "Server error while verifying OTP." });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Box sx={{ mt: 8, p: 4, border: "1px solid #ccc", borderRadius: 2, textAlign: "center" }}>
        <Typography variant="h5" gutterBottom>
          Rider Login
        </Typography>

        {message.text && <Alert severity={message.type} sx={{ mb: 2 }}>{message.text}</Alert>}

        {step === 1 && (
          <>
            <TextField
              fullWidth
              label="Mobile Number"
              variant="outlined"
              margin="normal"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
            />
            <Button
              fullWidth
              variant="contained"
              onClick={handleSendOtp}
              disabled={loading}
              sx={{ mt: 2 }}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          </>
        )}

        {step === 2 && (
          <>
            <TextField
              fullWidth
              label="Enter OTP"
              variant="outlined"
              margin="normal"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
            />
            <Button
              fullWidth
              variant="contained"
              onClick={handleVerifyOtp}
              disabled={loading}
              sx={{ mt: 2 }}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          </>
        )}

        <Box sx={{ mt: 3 }}>
          <Typography variant="body2">
            Don’t have an account?{" "}
            <Link to="/rider-register" style={{ textDecoration: "none" }}>
              Sign Up
            </Link>
          </Typography>
          <Typography variant="body2" sx={{ mt: 1 }}>
            Are you a User?{" "}
            <Link to="/login" style={{ textDecoration: "none" }}>
              Login as User
            </Link>
          </Typography>
        </Box>
      </Box>
    </Container>
  );
}
